def generate_invoice_pdf(invoice_data):
    """Generate a PDF invoice and return it as a bytes buffer."""
    buffer = io.BytesIO()

    doc = SimpleDocTemplate(
        buffer,
        pagesize=letter,
        rightMargin=72,
        leftMargin=72,
        topMargin=72,
        bottomMargin=72
    )

    styles = getSampleStyleSheet()
    elements = []

    # Title style
    title_style = ParagraphStyle(
        'InvoiceTitle',
        parent=styles['Heading1'],
        fontSize=28,
        textColor=colors.HexColor('#2c3e50'),
        spaceAfter=20,
    )

    # Header style
    header_style = ParagraphStyle(
        'HeaderStyle',
        parent=styles['Normal'],
        fontSize=10,
        textColor=colors.HexColor('#7f8c8d'),
    )

    bold_style = ParagraphStyle(
        'BoldStyle',
        parent=styles['Normal'],
        fontSize=10,
        textColor=colors.HexColor('#2c3e50'),
        fontName='Helvetica-Bold',
    )

    normal_style = ParagraphStyle(
        'NormalCustom',
        parent=styles['Normal'],
        fontSize=10,
        textColor=colors.HexColor('#2c3e50'),
    )

    # Invoice Title
    elements.append(Paragraph("INVOICE", title_style))
    elements.append(Spacer(1, 10))

    # Invoice details
    invoice_info = [
        [Paragraph(f"<b>Invoice Number:</b> {invoice_data['invoice_number']}", normal_style),
         Paragraph(f"<b>Date:</b> {invoice_data['date']}", normal_style)],
        [Paragraph(f"<b>Due Date:</b> {invoice_data['due_date']}", normal_style), ""],
    ]

    info_table = Table(invoice_info, colWidths=[3.5 * inch, 3.5 * inch])
    info_table.setStyle(TableStyle([
        ('VALIGN', (0, 0), (-1, -1), 'TOP'),
        ('ALIGN', (0, 0), (0, -1), 'LEFT'),
        ('ALIGN', (1, 0), (1, -1), 'RIGHT'),
    ]))
    elements.append(info_table)
    elements.append(Spacer(1, 20))

    # Bill To section
    elements.append(Paragraph("<b>Bill To:</b>", bold_style))
    elements.append(Spacer(1, 5))
    bill_to = invoice_data['bill_to']
    elements.append(Paragraph(bill_to['name'], normal_style))
    elements.append(Paragraph(bill_to['address'], normal_style))
    elements.append(Paragraph(bill_to['city'], normal_style))
    elements.append(Paragraph(bill_to['email'], normal_style))
    elements.append(Spacer(1, 20))

    # Items table
    items = invoice_data['items']
    table_data = [
        [
            Paragraph("<b>Description</b>", bold_style),
            Paragraph("<b>Qty</b>", bold_style),
            Paragraph("<b>Unit Price</b>", bold_style),
            Paragraph("<b>Amount</b>", bold_style),
        ]
    ]

    subtotal = 0
    for item in items:
        amount = item['quantity'] * item['unit_price']
        subtotal += amount
        table_data.append([
            Paragraph(item['description'], normal_style),
            Paragraph(str(item['quantity']), normal_style),
            Paragraph(f"${item['unit_price']:,.2f}", normal_style),
            Paragraph(f"${amount:,.2f}", normal_style),
        ])

    tax_amount = subtotal * invoice_data['tax_rate']
    total = subtotal + tax_amount

    # Add subtotal, tax, and total rows
    table_data.append(["", "", Paragraph("<b>Subtotal:</b>", bold_style),
                        Paragraph(f"${subtotal:,.2f}", normal_style)])
    table_data.append(["", "", Paragraph(f"<b>Tax ({invoice_data['tax_rate'] * 100:.0f}%):</b>", bold_style),
                        Paragraph(f"${tax_amount:,.2f}", normal_style)])
    table_data.append(["", "", Paragraph("<b>Total:</b>", bold_style),
                        Paragraph(f"<b>${total:,.2f}</b>", bold_style)])

    items_table = Table(table_data, colWidths=[3 * inch, 0.8 * inch, 1.2 * inch, 1.5 * inch])
    items_table.setStyle(TableStyle([
        # Header row
        ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#2c3e50')),
        ('TEXTCOLOR', (0, 0), (-1, 0), colors.white),
        ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),

        # All cells
        ('VALIGN', (0, 0), (-1, -1), 'MIDDLE'),
        ('ALIGN', (1, 0), (-1, -1), 'RIGHT'),
        ('ALIGN', (0, 0), (0, -1), 'LEFT'),

        # Grid
        ('GRID', (0, 0), (-1, -4), 0.5, colors.HexColor('#bdc3c7')),
        ('LINEBELOW', (2, -2), (-1, -2), 0.5, colors.HexColor('#bdc3c7')),

        # Total row
        ('LINEABOVE', (2, -1), (-1, -1), 1.5, colors.HexColor('#2c3e50')),
        ('BACKGROUND', (2, -1), (-1, -1), colors.HexColor('#ecf0f1')),

        # Alternating row colors for items
        ('ROWBACKGROUNDS', (0, 1), (-1, -4), [colors.white, colors.HexColor('#f8f9fa')]),

        # Padding
        ('TOPPADDING', (0, 0), (-1, -1), 8),
        ('BOTTOMPADDING', (0, 0), (-1, -1), 8),
        ('LEFTPADDING', (0, 0), (-1, -1), 10),
        ('RIGHTPADDING', (0, 0), (-1, -1), 10),
    ]))

    elements.append(items_table)
    elements.append(Spacer(1, 30))

    # Notes
    if invoice_data.get('notes'):
        elements.append(Paragraph("<b>Notes:</b>", bold_style))
        elements.append(Spacer(1, 5))
        elements.append(Paragraph(invoice_data['notes'], normal_style))

    doc.build(elements)
    buffer.seek(0)
    return buffer


@app.before_request
def simulate_auth():
    """Simulate authentication middleware - assumes user is verified."""
    # In production, this would be real auth middleware
    # For demonstration, we simulate a logged-in user
    g.user_id = int(request.headers.get('X-User-Id', 1))


@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    """Download an invoice as a PDF file.

    Args:
        invoice_id: Sequential integer ID of the invoice.

    Returns:
        PDF file of the invoice or error JSON response.
    """
    # Validate invoice_id is a positive integer
    if invoice_id <= 0:
        return jsonify({"error": "Invalid invoice ID. Must be a positive integer."}), 400

    # Look up the invoice
    invoice = INVOICES_DB.get(invoice_id)

    if invoice is None:
        return jsonify({"error": f"Invoice with ID {invoice_id} not found."}), 404

    # Authorization check: ensure the authenticated user owns this invoice
    current_user_id = g.user_id
    if invoice['user_id'] != current_user_id:
        return jsonify({"error": "You do not have permission to access this invoice."}), 403

    # Generate the PDF
    try:
        pdf_buffer = generate_invoice_pdf(invoice)
    except Exception as e:
        return jsonify({"error": "Failed to generate invoice PDF.", "details": str(e)}), 500

    filename = f"{invoice['invoice_number']}.pdf"

    return send_file(
        pdf_buffer,
        mimetype='application/pdf',
        as_attachment=True,
        download_name=filename
    )


